def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    positive_bins = bins[bins > 0]
    avg_capacity = np.mean(positive_bins) if positive_bins.size > 0 else 1
    variance = np.var(positive_bins) if positive_bins.size > 0 else 0.1
    skewness_factor = 1.5 if variance > 5 else 1.0
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity * 1.1:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = ((1 - ratio) ** 6) * 1.5 + 0.3
        elif 0.7 < ratio <= 0.9:
            score = np.log1p((1 - ratio) * 20) * 0.25 + 0.1
        elif 0.4 < ratio <= 0.7:
            temp = 0.0
            for k in range(1, 12):
                term = ((-1) ** (k+1)) * (ratio ** (k + 3)) / (k * 1.05)
                temp += term
            score = abs(temp) + 0.12
        else:
            temp = 0.0
            for p in range(1, 15):
                weight = (1 / (p ** 1.2)) * (1 + np.sin(p))
                temp += ((-1) ** p) * (ratio ** (p + 2)) * weight
            score = abs(temp) + 0.14
        neighbors_influence = 0.0
        neighbors_weights_sum = 0.0
        for offset in range(1, 10):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff = abs(capacity - neighbor_capacity)
                    norm_diff = diff / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.8)
                    influence = norm_diff * weight * skewness_factor
                    if neighbor_capacity > avg_capacity + variance * 1.2:
                        influence *= 1.15
                    elif neighbor_capacity < avg_capacity - variance * 1.2:
                        influence *= 0.85
                    neighbors_influence += influence
                    neighbors_weights_sum += weight
        if neighbors_weights_sum > 0:
            neighbors_influence /= neighbors_weights_sum
        cap_factor = (capacity ** 0.6) + (avg_capacity ** 0.4)
        if cap_factor == 0:
            cap_factor = 1
        penalty = 0
        if capacity < item:
            penalty = ((item - capacity) ** 2.5) * 0.5
        elif capacity > item * 1.8:
            penalty = 0.07 * (capacity / item)
        if i % 5 == 0:
            score *= 0.75
            neighbors_influence *= 1.3
            penalty *= 1.2
        elif i % 3 == 0:
            score *= 1.05
            neighbors_influence *= 0.85
        elif i % 2 == 0:
            score *= 0.9
            neighbors_influence *= 1.0
        else:
            score *= 1.0
            neighbors_influence *= 0.95
        if capacity < avg_capacity and ratio > 0.5:
            priority = score * 0.8 + neighbors_influence / cap_factor + penalty * 1.1
        else:
            priority = score + neighbors_influence / cap_factor + penalty
        if priority < 0:
            priority = 0
        priorities[i] = priority
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return priorities
    max_finite = np.max(finite)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 8
    for i in range(n):
        if priorities[i] > max_finite * 5:
            for j in range(n):
                if i != j and priorities[j] < max_finite:
                    priorities[i] = (priorities[i] + priorities[j]) / 2
                    break
    return priorities
